//  HELPERS
// ══════════════════════════════════════════════════════════════════════

function getTopics(level) {
  return Object.keys(WORDS_DB[level] || {});
}

function getWordsByTopic(level, topic) {
  return (WORDS_DB[level] || {})[topic] || [];
}

function getAllWords(level) {
  return Object.values(WORDS_DB[level] || {}).flat();
}

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function posLabel(pos) {
  const map = {
    verb: 'فعل', noun: 'اسم', adjective: 'صفة', adverb: 'ظرف',
    preposition: 'حرف جر', conjunction: 'حرف ربط',
  };
  return map[pos] || pos;
}
